    SELECT CAFE_SEQ.NEXTVAL FROM DUAL

INSERT INTO CAFE (
    CAFE_ID, USER_ID, BR_NO, CAFE_NAME, PHONE
  , POSTAL_CODE, ADDRESS, ADDRESS_DETAIL
) VALUES (
    #{cafeId}, #{userId}, #{brNo}, #{cafeName}, #{phone}
  , #{postalCode}, #{address}, #{addressDetail}
)

	INSERT INTO CAFE_DROP (CAFE_DROP_ID, CAFE_ID, DROP_REASON_ID)
	SELECT CAFE_DROP_SEQ.NEXTVAL, #{cafeId}, #{dropReasonId}
    FROM CAFE
    WHERE CAFE_ID = #{cafeId}
    AND USER_ID = #{userId}
